2697 template <typename Opnd_t> struct Signum_match {
2698   Opnd_t Val;
2699   Signum_match(const Opnd_t &V) : Val(V) {}
2700 
2701   template <typename OpTy> bool match(OpTy *V) {
2702     unsigned TypeSize = V->getType()->getScalarSizeInBits();
2703     if (TypeSize == 0)
2704       return false;
2705 
2706     unsigned ShiftWidth = TypeSize - 1;
2707     Value *OpL = nullptr, *OpR = nullptr;
2708 
2709     // This is the representation of signum we match:
2710     //
2711     //  signum(x) == (x >> 63) | (-x >>u 63)
2712     //
2713     // An i1 value is its own signum, so it's correct to match
2714     //
2715     //  signum(x) == (x >> 0)  | (-x >>u 0)
2716     //
2717     // for i1 values.
2718 
2719     auto LHS = m_AShr(m_Value(OpL), m_SpecificInt(ShiftWidth));
2720     auto RHS = m_LShr(m_Neg(m_Value(OpR)), m_SpecificInt(ShiftWidth));
2721     auto Signum = m_Or(LHS, RHS);
2722 
2723     return Signum.match(V) && OpL == OpR && Val.match(OpL);
2724   }
2725 };
